def two_sum(nums, target):
    hashmap = {}
    for i, num in enumerate(nums):
        if target - num in hashmap:
            return [hashmap[target - num], i]
        hashmap[num] = i

# Explanation:
# Use a hashmap to store each number and its index as we iterate.
# For every number, check if (target - num) already exists in the map.
# If yes, we found our pair — return both indices.
# Time Complexity: O(n) | Space Complexity: O(n)

def is_valid(s):
    stack = []
    mapping = {')': '(', '}': '{', ']': '['}

    for char in s:
        if char in mapping:
            top = stack.pop() if stack else '#'
            if mapping[char] != top:
                return False
        else:
            stack.append(char)

    return not stack

# Explanation:
# Use a stack — push opening brackets onto it.
# When a closing bracket is found, pop the stack and check if it matches.
# If stack is empty at the end, all brackets were matched correctly.
# Time Complexity: O(n) | Space Complexity: O(n)

def binary_search(nums, target):
    left, right = 0, len(nums) - 1

    while left <= right:
        mid = (left + right) // 2
        if nums[mid] == target:
            return mid
        elif nums[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return -1

# Explanation:
# Repeatedly halve the search space by comparing the middle element to target.
# If mid < target, search the right half; if mid > target, search the left half.
# Time Complexity: O(log n) | Space Complexity: O(1)

def num_islands(grid):
    def dfs(i, j):
        if i < 0 or j < 0 or i >= len(grid) or j >= len(grid[0]) or grid[i][j] == '0':
            return
        grid[i][j] = '0'  # mark visited
        dfs(i + 1, j)
        dfs(i - 1, j)
        dfs(i, j + 1)
        dfs(i, j - 1)

    count = 0
    for i in range(len(grid)):
        for j in range(len(grid[0])):
            if grid[i][j] == '1':
                dfs(i, j)
                count += 1

    return count

# Explanation:
# DFS flood-fill — when we find a '1', trigger DFS to mark the entire connected
# island as visited ('0') so it isn't counted again. Increment count per DFS call.
# Time Complexity: O(m × n) | Space Complexity: O(m × n) for recursion stack
